Loop through the array and track the maximum element.

```cpp
#include <vector>
#include <iostream>
using namespace std;
int findMax(vector<int>& arr) {
    // Initialize max with first element
    int max = arr[0];
    // Iterate through array to find larger elements
    for (int i = 1; i < arr.size(); i++) {
        if (arr[i] > max) max = arr[i];
    }
    return max;
}
int main() {
    vector<int> arr = {4, 2, 7, 1, 9};
    cout << findMax(arr); // Output: 9
}
