Sort activities by finish time and select non-overlapping ones.

```cpp
#include <vector>
#include <algorithm>
#include <iostream>
using namespace std;
struct Activity {
    int start, finish;
};
vector<Activity> selectActivities(vector<Activity>& activities) {
    // Sort by finish time
    sort(activities.begin(), activities.end(), [](Activity a, Activity b) {
        return a.finish < b.finish;
    });
    vector<Activity> result;
    result.push_back(activities[0]);
    int last = 0;
    // Select non-overlapping activities
    for (int i = 1; i < activities.size(); i++) {
        if (activities[i].start >= activities[last].finish) {
            result.push_back(activities[i]);
            last = i;
        }
    }
    return result;
}
int main() {
    vector<Activity> activities = {{1,4}, {3,5}, {6,7}};
    auto result = selectActivities(activities);
    cout << result.size(); // Output: 2
}
```

Use two pointers to swap elements from both ends.

```cpp
#include <vector>
#include <iostream>
using namespace std;
void reverseArray(vector<int>& arr) {
    int left = 0, right = arr.size() - 1;
    // Swap elements until pointers meet
    while (left < right) {
        swap(arr[left], arr[right]);
        left++; right--;
    }
}
int main() {
    vector<int> arr = {1, 2, 3, 4};
    reverseArray(arr);
    for (int x : arr) cout << x << " "; // Output: 4 3 2 1
