Sort items by value/weight ratio and fill knapsack greedily.

```cpp
#include <vector>
#include <algorithm>
#include <iostream>
using namespace std;
struct Item {
    double value, weight;
};
double fractionalKnapsack(vector<Item>& items, double W) {
    // Sort by value/weight ratio
    sort(items.begin(), items.end(), [](Item a, Item b) {
        return a.value / a.weight > b.value / b.weight;
    });
    double total = 0;
    // Fill knapsack
    for (auto& item : items) {
        if (W >= item.weight) {
            total += item.value;
            W -= item.weight;
        } else {
            total += item.value * (W / item.weight);
            break;
        }
    }
    return total;
}
int main() {
    vector<Item> items = {{60,10}, {100,20}, {120,30}};
    cout << fractionalKnapsack(items, 50); // Output: 240
}
```

