Use a priority queue to select the vertex with minimum distance.

```cpp
#include <vector>
#include <queue>
#include <iostream>
using namespace std;
vector<int> dijkstra(vector<vector<pair<int,int>>>& adj, int src) {
    vector<int> dist(adj.size(), INT_MAX);
    priority_queue<pair<int,int>, vector<pair<int,int>>, greater<>> pq;
    dist[src] = 0; pq.push({0, src});
    // Update distances using priority queue
    while (!pq.empty()) {
        int u = pq.top().second; pq.pop();
        for (auto& [v, w] : adj[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }
    return dist;
}
int main() {
    vector<vector<pair<int,int>>> adj = {{{2,2},{3,3}}, {{4,1}}, {}, {{2,1}}, {}};
    auto dist = dijkstra(adj, 1);
    for (int d : dist) if (d != INT_MAX) cout << d << " "; // Output: 0 2 3 3
}
```

Relax all edges |V|-1 times to find shortest paths.

```cpp
#include <vector>
#include <iostream>
using namespace std;
vector<int> bellmanFord(vector<vector<pair<int,int>>>& adj, int src) {
    vector<int> dist(adj.size(), INT_MAX);
    dist[src] = 0;
    // Relax edges |V|-1 times
    for (int i = 1; i < adj.size(); i++) {
        for (int u = 0; u < adj.size(); u++) {
            for (auto& [v, w] : adj[u]) {
                if (dist[u] != INT_MAX && dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                }
            }
        }
    }
    return dist;
}
int main() {
    vector<vector<pair<int,int>>> adj = {{{2,-1},{3,-2}}, {}, {{4,3}}, {}, {}};
    auto dist = bellmanFord(adj, 1);
    for (int d : dist) if (d != INT_MAX) cout << d << " "; // Output: 0 -1 -2 -2
}
