Use dynamic programming to update distances via intermediate vertices.

```cpp
#include <vector>
#include <iostream>
using namespace std;
void floydWarshall(vector<vector<int>>& graph) {
    int n = graph.size();
    vector<vector<int>> dist = graph;
    // Update distances via each vertex
    for (int k = 0; k < n; k++) {
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (dist[i][k] != INT_MAX && dist[k][j] != INT_MAX && dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
    }
    // Print distances
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cout << (dist[i][j] == INT_MAX ? "INF" : to_string(dist[i][j])) << " ";
        }
        cout << endl;
    }
}
int main() {
    vector<vector<int>> graph = {{0,2,3,INT_MAX}, {INT_MAX,0,INT_MAX,1}, {INT_MAX,INT_MAX,0,4}, {INT_MAX,INT_MAX,INT_MAX,0}};
    floydWarshall(graph); // Output: Shortest paths matrix
}
