Use a priority queue to select minimum-weight edges.

```cpp
#include <vector>
#include <queue>
#include <iostream>
using namespace std;
vector<int> prim(vector<vector<pair<int,int>>>& adj) {
    vector<int> parent(adj.size(), -1);
    vector<bool> inMST(adj.size(), false);
    vector<int> key(adj.size(), INT_MAX);
    priority_queue<pair<int,int>, vector<pair<int,int>>, greater<>> pq;
    key[0] = 0; pq.push({0, 0});
    // Build MST
    while (!pq.empty()) {
        int u = pq.top().second; pq.pop();
        if (inMST[u]) continue;
        inMST[u] = true;
        for (auto& [v, w] : adj[u]) {
            if (!inMST[v] && w < key[v]) {
                key[v] = w; parent[v] = u;
                pq.push({w, v});
            }
        }
    }
    return parent;
}
int main() {
    vector<vector<pair<int,int>>> adj = {{{2,2},{3,3}}, {{4,1}}, {{4,4}}, {{2,1}}, {}};
    auto parent = prim(adj);
    for (int i = 1; i < parent.size(); i++) if (parent[i] != -1) cout << i << "→" << parent[i] << " "; // Output: 2→1 3→1 4→2
}
