Use Union-Find to avoid cycles.

```cpp
#include <vector>
#include <algorithm>
#include <iostream>
using namespace std;
struct Edge { int u, v, w; };
int find(vector<int>& parent, int x) {
    if (parent[x] != x) parent[x] = find(parent, parent[x]);
    return parent[x];
}
vector<Edge> kruskal(vector<Edge>& edges, int n) {
    vector<Edge> mst;
    vector<int> parent(n);
    for (int i = 0; i < n; i++) parent[i] = i;
    // Sort edges by weight
    sort(edges.begin(), edges.end(), [](Edge a, Edge b) { return a.w < b.w; });
    // Add non-cyclic edges
    for (auto& e : edges) {
        int pu = find(parent, e.u), pv = find(parent, e.v);
        if (pu != pv) {
            mst.push_back(e);
            parent[pu] = pv;
        }
    }
    return mst;
}
int main() {
    vector<Edge> edges = {{1,2,2}, {2,4,1}, {1,3,3}, {3,4,4}};
    auto mst = kruskal(edges, 5);
    for (auto& e : mst) cout << e.u << "→" << e.v << "(" << e.w << ") "; // Output: 2→4(1) 1→2(2)
}
