Use Union-Find to check if an edge connects vertices in the same set.

```cpp
#include <vector>
#include <iostream>
using namespace std;
struct UnionFind {
    vector<int> parent, rank;
    UnionFind(int n) : parent(n), rank(n, 0) {
        for (int i = 0; i < n; i++) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
    bool unite(int x, int y) {
        int px = find(x), py = find(y);
        if (px == py) return false;
        if (rank[px] < rank[py]) swap(px, py);
        parent[py] = px;
        if (rank[px] == rank[py]) rank[px]++;
        return true;
    }
};
bool hasCycle(vector<vector<int>>& edges, int n) {
    UnionFind uf(n);
    // Check each edge
    for (auto& e : edges) {
        if (!uf.unite(e[0], e[1])) return true;
    }
    return false;
}
int main() {
    vector<vector<int>> edges = {{1,2}, {2,3}, {3,1}};
    cout << hasCycle(edges, 4); // Output: 1
}
```

Use DFS with a stack to identify SCCs.

```cpp
#include <vector>
#include <stack>
#include <iostream>
using namespace std;
void dfs(vector<vector<int>>& adj, int v, vector<int>& disc, vector<int>& low, stack<int>& st, vector<bool>& inStack, vector<vector<int>>& sccs) {
    static int time = 0;
    disc[v] = low[v] = ++time;
    st.push(v); inStack[v] = true;
    // Explore neighbors
    for (int u : adj[v]) {
        if (disc[u] == -1) {
            dfs(adj, u, disc, low, st, inStack, sccs);
            low[v] = min(low[v], low[u]);
        } else if (inStack[u]) {
            low[v] = min(low[v], disc[u]);
        }
    }
    // Form SCC
    if (disc[v] == low[v]) {
        vector<int> scc;
        while (st.top() != v) {
            scc.push_back(st.top()); inStack[st.top()] = false; st.pop();
        }
        scc.push_back(st.top()); inStack[st.top()] = false; st.pop();
        sccs.push_back(scc);
    }
}
vector<vector<int>> tarjanSCC(vector<vector<int>>& adj) {
    int n = adj.size();
    vector<int> disc(n, -1), low(n, -1);
    vector<bool> inStack(n, false);
    stack<int> st;
    vector<vector<int>> sccs;
    for (int v = 0; v < n; v++) {
        if (disc[v] == -1) dfs(adj, v, disc, low, st, inStack, sccs);
    }
    return sccs;
}
int main() {
    vector<vector<int>> adj = {{}, {2}, {4}, {}, {3}};
    auto sccs = tarjanSCC(adj);
    for (auto& scc : sccs) {
        for (int v : scc) cout << v << " ";
        cout << endl;
    } // Output: 1 2 3
}
```

