Build LPS table to skip redundant comparisons.

```cpp
#include <string>
#include <vector>
#include <iostream>
using namespace std;
vector<int> computeLPS(string pattern) {
    int m = pattern.size(), len = 0;
    vector<int> lps(m, 0);
    for (int i = 1; i < m; i++) {
        while (len > 0 && pattern[i] != pattern[len]) len = lps[len - 1];
        if (pattern[i] == pattern[len]) len++;
        lps[i] = len;
    }
    return lps;
}
vector<int> kmpMatch(string text, string pattern) {
    vector<int> result, lps = computeLPS(pattern);
    int n = text.size(), m = pattern.size(), j = 0;
    // Match pattern in text
    for (int i = 0; i < n; i++) {
        while (j > 0 && text[i] != pattern[j]) j = lps[j - 1];
        if (text[i] == pattern[j]) j++;
        if (j == m) {
            result.push_back(i - j + 1);
            j = lps[j - 1];
        }
    }
    return result;
}
int main() {
    string text = "ABABCD", pattern = "ABABC";
    auto matches = kmpMatch(text, pattern);
    for (int i : matches) cout << i << " "; // Output: 0
}
```

Compute and compare hashes of pattern and text windows.

```cpp
#include <string>
#include <vector>
#include <iostream>
using namespace std;
vector<int> rabinKarp(string text, string pattern) {
    int d = 256, q = 101, n = text.size(), m = pattern.size();
    vector<int> result;
    long long p = 0, t = 0, h = 1;
    // Compute hash multiplier
    for (int i = 0; i < m - 1; i++) h = (h * d) % q;
    // Initial hash for pattern and first window
    for (int i = 0; i < m; i++) {
        p = (d * p + pattern[i]) % q;
        t = (d * t + text[i]) % q;
    }
    // Slide window and compare hashes
    for (int i = 0; i <= n - m; i++) {
        if (p == t) {
            bool match = true;
            for (int j = 0; j < m; j++)
                if (text[i + j] != pattern[j]) { match = false; break; }
            if (match) result.push_back(i);
        }
        if (i < n - m) {
            t = (d * (t - text[i] * h) + text[i + m]) % q;
            if (t < 0) t += q;
        }
    }
    return result;
}
int main() {
    string text = "ABCDE", pattern = "BCD";
    auto matches = rabinKarp(text, pattern);
    for (int i : matches) cout << i << " "; // Output: 1
}
```

Use dynamic programming to build a 2D table.

```cpp
#include <string>
#include <vector>
#include <iostream>
using namespace std;
int longestCommonSubstring(string s1, string s2) {
    int m = s1.size(), n = s2.size(), maxLen = 0;
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (s1[i-1] == s2[j-1]) {
                dp[i][j] = dp[i-1][j-1] + 1;
                maxLen = max(maxLen, dp[i][j]);
            }
        }
    }
    return maxLen;
}
int main() {
    string s1 = "ABCDGH", s2 = "AEDFHR";
    cout << longestCommonSubstring(s1, s2); // Output: 3
}
