Expand around center to find palindromes.

```cpp
#include <string>
#include <iostream>
using namespace std;
string longestPalindromic(string s) {
    int start = 0, maxLen = 1;
    for (int i = 0; i < s.size(); i++) {
        // Odd length palindrome
        int left = i, right = i;
        while (left >= 0 && right < s.size() && s[left] == s[right]) {
            if (right - left + 1 > maxLen) {
                start = left; maxLen = right - left + 1;
            }
            left--; right++;
        }
        // Even length palindrome
        left = i; right = i + 1;
        while (left >= 0 && right < s.size() && s[left] == s[right]) {
            if (right - left + 1 > maxLen) {
                start = left; maxLen = right - left + 1;
            }
            left--; right++;
        }
    }
    return s.substr(start, maxLen);
}
int main() {
    string s = "babad"; cout << longestPalindromic(s); // Output: bab
}
