Use Z-algorithm to compute Z-values efficiently.

```cpp
#include <vector>
#include <string>
#include <iostream>
using namespace std;
vector<int> zAlgorithm(string s) {
    int n = s.size();
    vector<int> z(n, 0);
    int left = 0, right = 0;
    for (int i = 1; i < n; i++) {
        if (i > right) {
            left = right = i;
            while (right < n && s[right] == s[right - left]) right++;
            z[i] = right - left; right--;
        } else {
            int k = i - left;
            if (z[k] < right - i + 1) z[i] = z[k];
            else {
                left = i;
                while (right < n && s[right] == s[right - left]) right++;
                z[i] = right - left; right--;
            }
        }
    }
    return z;
}
int main() {
    string s = "aabxaabxaabx"; auto z = zAlgorithm(s);
    for (int x : z) cout << x << " "; // Output: 0 1 0 2 ...
}
