Use divide and conquer to find the target.

```cpp
#include <vector>
#include <iostream>
using namespace std;
int binarySearch(vector<int>& arr, int target) {
    int left = 0, right = arr.size() - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == target) return mid;
        else if (arr[mid] < target) left = mid + 1;
        else right = mid - 1;
    }
    return -1;
}
int main() {
    vector<int> arr = {1, 3, 5, 7, 9}; cout << binarySearch(arr, 5); // Output: 2
}
```

Jump exponentially and use binary search in the range.

```cpp
#include <vector>
#include <iostream>
using namespace std;
int binarySearch(vector<int>& arr, int left, int right, int target) {
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] == target) return mid;
        else if (arr[mid] < target) left = mid + 1;
        else right = mid - 1;
    }
    return -1;
}
int exponentialSearch(vector<int>& arr, int target) {
    if (arr[0] == target) return 0;
    int i = 1;
    while (i < arr.size() && arr[i] <= target) i *= 2;
    return binarySearch(arr, i / 2, min(i, (int)arr.size() - 1), target);
}
int main() {
    vector<int> arr = {1, 3, 5, 7, 9, 11}; cout << exponentialSearch(arr, 7); // Output: 3
}
```

Jump by block size and linear search in the block.

```cpp
#include <vector>
#include <iostream>
using namespace std;
int jumpSearch(vector<int>& arr, int target) {
    int n = arr.size(), step = sqrt(n);
    int prev = 0;
    while (arr[min(step, n) - 1] < target) {
        prev = step;
        step += sqrt(n);
        if (prev >= n) return -1;
    }
    while (arr[prev] < target) {
        prev++;
        if (prev == min(step, n)) return -1;
    }
    return arr[prev] == target ? prev : -1;
}
int main() {
    vector<int> arr = {1, 3, 5, 7, 9}; cout << jumpSearch(arr, 7); // Output: 3
}
```

Divide array into halves and merge sorted halves.

```cpp
#include <vector>
#include <iostream>
using namespace std;
void merge(vector<int>& arr, int left, int mid, int right) {
    int n1 = mid - left + 1, n2 = right - mid;
    vector<int> L(n1), R(n2);
    for (int i = 0; i < n1; i++) L[i] = arr[left + i];
    for (int j = 0; j < n2; j++) R[j] = arr[mid + 1 + j];
    int i = 0, j = 0, k = left;
    while (i < n1 && j < n2) {
        if (L[i] <= R[j]) arr[k++] = L[i++];
        else arr[k++] = R[j++];
    }
    while (i < n1) arr[k++] = L[i++];
    while (j < n2) arr[k++] = R[j++];
}
void mergeSort(vector<int>& arr, int left, int right) {
    if (left < right) {
        int mid = left + (right - left) / 2;
        mergeSort(arr, left, mid);
        mergeSort(arr, mid + 1, right);
        merge(arr, left, mid, right);
    }
}
int main() {
    vector<int> arr = {64, 34, 25, 12, 22}; mergeSort(arr, 0, arr.size() - 1);
    for (int x : arr) cout << x << " "; // Output: 12 22 25 34 64
}
