```cpp
#include <vector>
#include <iostream>
using namespace std;
int fibSearch(vector<int>& arr, int target) {
    int n = arr.size();
    int fib2 = 0, fib1 = 1, fib = fib1 + fib2;
    while (fib < n) {
        fib2 = fib1; fib1 = fib; fib = fib1 + fib2;
    }
    int offset = -1;
    while (fib > 1) {
        int i = min(offset + fib2, n - 1);
        if (arr[i] < target) {
            fib = fib2; fib1 = fib1 - fib2; fib2 = fib - fib1;
            offset = i;
        } else if (arr[i] > target) {
            fib = fib1; fib1 = fib2; fib2 = fib - fib1;
        } else return i;
    }
    if (fib1 && arr[offset + 1] == target) return offset + 1;
    return -1;
}
