Build trie and use failure links for matching.

```cpp
#include <vector>
#include <string>
#include <queue>
#include <iostream>
using namespace std;

struct TrieNode {
    TrieNode* children[26] = {nullptr};
    TrieNode* fail = nullptr;
    bool isEnd = false;
    int index;
};

class AhoCorasick {
    TrieNode* root;
public:
    AhoCorasick(vector<string>& patterns) {
        root = new TrieNode();
        for (int i = 0; i < patterns.size(); i++) addPattern(patterns[i], i);
        buildFailureLinks();
    }
    void addPattern(string pattern, int index) {
        TrieNode* curr = root;
        for (char c : pattern) {
            int idx = c - 'a';
            if (!curr->children[idx]) curr->children[idx] = new TrieNode();
            curr = curr->children[idx];
        }
        curr->isEnd = true;
        curr->index = index;
    }
    void buildFailureLinks() {
        queue<TrieNode*> q;
        root->fail = root;
        for (int i = 0; i < 26; i++) {
            if (root->children[i]) {
                root->children[i]->fail = root;
                q.push(root->children[i]);
            }
        }
        while (!q.empty()) {
            TrieNode* curr = q.front();
            q.pop();
            for (int i = 0; i < 26; i++) {
                if (curr->children[i]) {
                    TrieNode* child = curr->children[i];
                    q.push(child);
                    TrieNode* failNode = curr->fail;
                    while (failNode != root && !failNode->children[i]) {
                        failNode = failNode->fail;
                    }
                    child->fail = failNode->children[i] ? failNode->children[i] : root;
                }
            }
        }
    }
    vector<int> search(string text) {
        vector<int> matches;
        TrieNode* curr = root;
        for (int i = 0; i < text.size(); i++) {
            int idx = text[i] - 'a';
            while (curr != root && !curr->children[idx]) {
                curr = curr->fail;
            }
            curr = curr->children[idx] ? curr->children[idx] : root;
            TrieNode* temp = curr;
            while (temp != root) {
                if (temp->isEnd) matches.push_back({i - (temp->index), temp->index});
                temp = temp->fail;
            }
        }
        return matches;
    }
};

int main() {
    vector<string> patterns = {"he", "she", "his", "hers"};
    AhoCorasick ac(patterns);
    string text = "ahishers";
    auto matches = ac.search(text);
    for (auto& match : matches) cout << match.first << " " << match.second << endl;
    // Output: 1 he, 3 she, 4 his, 5 hers
}
