Use Manacher’s algorithm with a palindrome radius array.

```cpp
#include <string>
#include <vector>
#include <iostream>
using namespace std;

string manacher(string s) {
    string t = "#";
    for (char c : s) {
        t += c;
        t += "#";
    }
    int n = t.size();
    vector<int> p(n, 0);
    int center = 0, right = 0;
    for (int i = 0; i < n; i++) {
        if (i < right) p[i] = min(right - i, p[2 * center - i]);
        int left = i - (p[i] + 1), right = i + (p[i] + 1);
        while (left >= 0 && right < n && t[left] == t[right]) {
            p[i]++;
            left--; right++;
        }
        if (i + p[i] > right) {
            center = i;
            right = i + p[i];
        }
    }
    int maxLen = 0, centerIdx = 0;
    for (int i = 0; i < n; i++) {
        if (p[i] > maxLen) {
            maxLen = p[i];
            centerIdx = i;
        }
    }
    int start = (centerIdx - maxLen) / 2;
    return s.substr(start, maxLen);
}

int main() {
    string s = "babad"; cout << manacher(s) << endl; // Output: bab
}
