```cpp
#include <vector>
#include <algorithm>
#include <iostream>
using namespace std;
struct Job { int id, deadline, profit; };
int jobScheduling(vector<Job>& jobs) {
    sort(jobs.begin(), jobs.end(), [](Job a, Job b) { return a.profit > b.profit; });
    int maxDeadline = 0;
    for (auto& job : jobs) maxDeadline = max(maxDeadline, job.deadline);
    vector<int> slot(maxDeadline, -1);
    int totalProfit = 0;
    // Assign jobs to latest possible slot
    for (auto& job : jobs) {
        for (int j = min(maxDeadline, job.deadline) - 1; j >= 0; j--) {
            if (slot[j] == -1) {
                slot[j] = job.id;
                totalProfit += job.profit;
                break;
            }
        }
    }
    return totalProfit;
}
int main() {
