    while (!st.empty()) {
        int v = st.top(); st.pop();
        if (!visited[v]) {
            vector<int> scc;
            dfs2(adjT, v, visited, scc);
            sccs.push_back(scc);
        }
    }
    return sccs;
}
int main() {
    vector<vector<int>> adj = {{}, {2}, {3}, {1}};
    auto sccs = kosaraju(adj);
    for (auto& scc : sccs) { for (int v : scc) cout << v << " "; cout << endl; } // Output: 0 1 2 3
}
