Compute Z array to find pattern matches.

```cpp
#include <string>
#include <vector>
#include <iostream>
using namespace std;
vector<int> zAlgorithm(string s) {
    int n = s.size(), l = 0, r = 0;
    vector<int> z(n, 0);
    for (int i = 1; i < n; i++) {
        if (i <= r) z[i] = min(r - i + 1, z[i - l]);
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) z[i]++;
        if (i + z[i] - 1 > r) l = i, r = i + z[i] - 1;
    }
    return z;
}
vector<int> findMatches(string text, string pattern) {
    string s = pattern + "$" + text;
    vector<int> z = zAlgorithm(s), result;
    for (int i = 0; i < s.size(); i++) {
        if (z[i] == pattern.size()) result.push_back(i - pattern.size() - 1);
    }
    return result;
}
int main() {
    string text = "AABAAC", pattern = "AA";
    auto matches = findMatches(text, pattern);
    for (int i : matches) cout << i << " "; // Output: 0 3
}
