Use DSU to merge connected vertices.

```cpp
#include <vector>
#include <iostream>
using namespace std;
struct DSU {
    vector<int> parent, rank;
    DSU(int n) : parent(n), rank(n, 0) {
        for (int i = 0; i < n; i++) parent[i] = i;
    }
    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }
    void unite(int x, int y) {
        int px = find(x), py = find(y);
        if (px == py) return;
        if (rank[px] < rank[py]) swap(px, py);
        parent[py] = px;
        if (rank[px] == rank[py]) rank[px]++;
    }
};
int countComponents(vector<vector<int>>& edges, int n) {
    DSU dsu(n);
    for (auto& e : edges) dsu.unite(e[0], e[1]);
    vector<bool> seen(n, false);
    int count = 0;
    for (int i = 0; i < n; i++) {
        if (!seen[dsu.find(i)]) {
            seen[dsu.find(i)] = true;
            count++;
        }
    }
    return count;
}
int main() {
    vector<vector<int>> edges = {{0,1}, {1,2}, {3,4}};
    cout << countComponents(edges, 5); // Output: 2
}
