struct Point { int x, y; };
long long cross(Point a, Point b, Point c) {
    return (b.x - a.x) * (long long)(c.y - a.y) - (b.y - a.y) * (long long)(c.x - a.x);
}
bool isConvex(vector<Point>& points) {
    int n = points.size();
    long long prev = 0;
    for (int i = 0; i < n; i++) {
        long long curr = cross(points[i], points[(i+1)%n], points[(i+2)%n]);
        if (curr != 0) {
            if (prev == 0) prev = curr;
            else if (curr * prev < 0) return false;
        }
    }
    return true;
}
