Use modular arithmetic to combine solutions.

```cpp
#include <vector>
#include <iostream>
using namespace std;
long long modInverse(long long a, long long m) {
    long long m0 = m, x0 = 0, x1 = 1;
    while (m != 0) {
        long long q = a / m, t = m;
        m = a % m; a = t;
        t = x0; x0 = x1 - q * x0; x1 = t;
    }
    return x1 < 0 ? x1 + m0 : x1;
}
long long crt(vector<int>& a, vector<int>& m) {
    long long prod = 1, result = 0;
    for (int x : m) prod *= x;
    for (int i = 0; i < a.size(); i++) {
        long long p = prod / m[i];
        result += a[i] * p * modInverse(p, m[i]);
    }
    return result % prod;
}
int main() {
