double cost(vector<pair<int,int>>& points, int i, int j, int k) {
    return sqrt(pow(points[i].first - points[j].first, 2) + pow(points[i].second - points[j].second, 2)) +
           sqrt(pow(points[j].first - points[k].first, 2) + pow(points[j].second - points[k].second, 2)) +
           sqrt(pow(points[k].first - points[i].first, 2) + pow(points[k].second - points[i].second, 2));
}
double minTriangulation(vector<pair<int,int>>& points) {
    int n = points.size();
    vector<vector<double>> dp(n, vector<double>(n, 1e9));
    for (int i = 0; i < n - 1; i++) dp[i][i+1] = 0;
    for (int len = 3; len <= n; len++) {
        for (int i = 0; i <= n - len; i++) {
            int j = i + len - 1;
            for (int k = i + 1; k < j; k++) {
                dp[i][j] = min(dp[i][j], dp[i][k] + dp[k][j] + cost(points, i, k, j));
            }
        }
    }
    return dp[0][n-1];
}
