#include <string>
#include <vector>
#include <iostream>
using namespace std;
string minWindow(string s, string t) {
    vector<int> freq(128, 0);
    int required = t.size(), formed = 0;
    for (char c : t) freq[c]++;
    int left = 0, minLen = INT_MAX, minLeft = 0;
    for (int right = 0; right < s.size(); right++) {
        if (freq[s[right]] > 0) formed++;
        freq[s[right]]--;
        while (formed == required) {
            if (right - left + 1 < minLen) {
                minLen = right - left + 1;
                minLeft = left;
            }
            if (freq[s[left]] == 0) formed--;
            freq[s[left]]++;
            left++;
        }
    }
    return minLen == INT_MAX ? "" : s.substr(minLeft, minLen);
}
int main() {
    string s = "ADOBECODEBANC", t = "ABC";
    cout << minWindow(s, t); // Output: BANC
}
