Use a tree to store range sums.

```cpp
#include <vector>
#include <iostream>
using namespace std;
struct SegmentTree {
    vector<long long> tree;
    int n;
    SegmentTree(vector<int>& arr) : n(arr.size()) {
        tree.resize(4 * n);
        build(arr, 0, 0, n - 1);
    }
    void build(vector<int>& arr, int node, int start, int end) {
        if (start == end) { tree[node] = arr[start]; return; }
        int mid = (start + end) / 2;
        build(arr, 2 * node + 1, start, mid);
        build(arr, 2 * node + 2, mid + 1, end);
        tree[node] = tree[2 * node + 1] + tree[2 * node + 2];
    }
    void update(int idx, int val, int node, int start, int end) {
        if (start == end) { tree[node] = val; return; }
        int mid = (start + end) / 2;
        if (idx <= mid) update(idx, val, 2 * node + 1, start, mid);
        else update(idx, val, 2 * node + 2, mid + 1, end);
        tree[node] = tree[2 * node + 1] + tree[2 * node + 2];
    }
    long long query(int l, int r, int node, int start, int end) {
        if (r < start || l > end) return 0;
        if (l <= start && r >= end) return tree[node];
        int mid = (start + end) / 2;
        return query(l, r, 2 * node + 1, start, mid) + query(l, r, 2 * node + 2, mid + 1, end);
    }
};
int main() {
    vector<int> arr = {1,3,5,7,9};
    SegmentTree st(arr);
    cout << st.query(1, 3, 0, 0, arr.size() - 1); // Output: 15
}
