Use binary search to partition arrays.

```cpp
#include <vector>
#include <iostream>
using namespace std;
double findMedianSortedArrays(vector<int>& nums1, vector<int>& nums2) {
    if (nums1.size() > nums2.size()) swap(nums1, nums2);
    int m = nums1.size(), n = nums2.size();
    int left = 0, right = m;
    while (left <= right) {
        int px = (left + right) / 2, py = (m + n + 1) / 2 - px;
        int l1 = px == 0 ? INT_MIN : nums1[px-1];
        int r1 = px == m ? INT_MAX : nums1[px];
        int l2 = py == 0 ? INT_MIN : nums2[py-1];
        int r2 = py == n ? INT_MAX : nums2[py];
        if (l1 <= r2 && l2 <= r1) {
            if ((m + n) % 2 == 0) return (max(l1, l2) + min(r1, r2)) / 2.0;
            return max(l1, l2);
        }
        if (l1 > r2) right = px - 1;
        else left = px + 1;
    }
    return 0;
}
int main() {
    vector<int> nums1 = {1,3}, nums2 = {2};
    cout << findMedianSortedArrays(nums1, nums2); // Output: 2
}
