Use a doubly linked list and hash map.

```cpp
#include <unordered_map>
#include <iostream>
using namespace std;
struct Node {
    int key, val;
    Node* prev, *next;
    Node(int k, int v) : key(k), val(v), prev(nullptr), next(nullptr) {}
};
class LRUCache {
private:
    int capacity;
    unordered_map<int, Node*> cache;
    Node* head, *tail;
    void moveToFront(Node* node) {
        if (node == head) return;
        if (node == tail) tail = node->prev;
        node->prev->next = node->next;
        if (node->next) node->next->prev = node->prev;
        node->next = head;
        node->prev = nullptr;
        head->prev = node;
        head = node;
    }
public:
    LRUCache(int c) : capacity(c) {
        head = tail = nullptr;
    }
    int get(int key) {
        if (!cache.count(key)) return -1;
        Node* node = cache[key];
        moveToFront(node);
        return node->val;
    }
    void put(int key, int value) {
        if (cache.count(key)) {
            cache[key]->val = value;
            moveToFront(cache[key]);
            return;
        }
        Node* node = new Node(key, value);
        if (!head) head = tail = node;
        else {
            node->next = head;
            head->prev = node;
            head = node;
        }
        cache[key] = node;
        if (cache.size() > capacity) {
            cache.erase(tail->key);
            Node* temp = tail;
            tail = tail->prev;
            if (tail) tail->next = nullptr;
            delete temp;
        }
    }
};
int main() {
    LRUCache cache(2);
    cache.put(1, 1);
    cache.put(2, 2);
    cout << cache.get(1) << " "; // Output: 1
    cache.put(3, 3);
    cout << cache.get(2) << " "; // Output: -1
}
