Use a node structure with character arrays.

```cpp
#include <string>
#include <iostream>
using namespace std;
struct TrieNode {
    TrieNode* children[26];
    bool isEnd;
    TrieNode() : isEnd(false) { for (int i = 0; i < 26; i++) children[i] = nullptr; }
};
class Trie {
private:
    TrieNode* root;
public:
    Trie() { root = new TrieNode(); }
    void insert(string word) {
        TrieNode* node = root;
        for (char c : word) {
            int idx = c - 'a';
            if (!node->children[idx]) node->children[idx] = new TrieNode();
            node = node->children[idx];
        }
        node->isEnd = true;
    }
    bool search(string word) {
        TrieNode* node = root;
        for (char c : word) {
            int idx = c - 'a';
            if (!node->children[idx]) return false;
            node = node->children[idx];
        }
        return node->isEnd;
    }
    bool startsWith(string prefix) {
        TrieNode* node = root;
        for (char c : prefix) {
            int idx = c - 'a';
            if (!node->children[idx]) return false;
            node = node->children[idx];
        }
        return true;
    }
};
int main() {
    Trie trie;
    trie.insert("apple");
    cout << trie.search("apple") << " "; // Output: 1
    cout << trie.search("app") << " ";   // Output: 0
    cout << trie.startsWith("app") << " "; // Output: 1
}
